# =============================================================================
# BUNDLED IMPORT HOOK
# =============================================================================
# - Loads open_webui_cometapi_pipe.* from embedded sources
# - Populates linecache so inspect.getsource() works

from __future__ import annotations

import linecache
import sys
from importlib.abc import Loader, MetaPathFinder
from importlib.machinery import ModuleSpec

_BUNDLED_SOURCES: dict[str, str] = {}

def _bundled_source(fullname: str) -> str:
    return _BUNDLED_SOURCES.get(fullname, "")

def _bundled_has_module(fullname: str) -> bool:
    return fullname in _BUNDLED_SOURCES

def _bundled_is_package(fullname: str) -> bool:
    prefix = fullname + "."
    return any(name.startswith(prefix) for name in _BUNDLED_SOURCES)

class _BundledModuleFinder(MetaPathFinder):
    def find_spec(self, fullname, path, target=None):
        if not _bundled_has_module(fullname):
            return None
        return ModuleSpec(
            fullname,
            _BundledModuleLoader(fullname),
            is_package=_bundled_is_package(fullname),
        )

class _BundledModuleLoader(Loader):
    def __init__(self, fullname: str):
        self.fullname = fullname

    def create_module(self, spec):
        return None  # default module creation

    def exec_module(self, module):
        if _bundled_is_package(self.fullname):
            module.__path__ = []
            module.__package__ = self.fullname
        else:
            module.__package__ = self.fullname.rpartition(".")[0] or self.fullname

        module.__file__ = f"<bundled:{self.fullname}>"

        source = _bundled_source(self.fullname)
        if not source.strip():
            return

        # Make inspect.getsource() work for bundled modules
        linecache.cache[module.__file__] = (
            len(source),
            None,
            source.splitlines(True),
            module.__file__,
        )

        code = compile(source, module.__file__, "exec")
        exec(code, module.__dict__)

def _install_bundled_finder() -> None:
    for finder in sys.meta_path:
        if isinstance(finder, _BundledModuleFinder):
            return
    sys.meta_path.insert(0, _BundledModuleFinder())

_install_bundled_finder()

